package com.socialblog.follower.application;import com.fasterxml.jackson.core.JsonProcessingException;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.follower.domain.*;import com.socialblog.follower.web.CorrelationIdProvider;import org.springframework.stereotype.Component;import java.time.Instant;import java.util.*;@Component public class DomainEventFactory{private final ObjectMapper json;private final CorrelationIdProvider ids;public DomainEventFactory(ObjectMapper j,CorrelationIdProvider i){json=j;ids=i;}public OutboxEvent followed(Follow f){return event("UserFollowed",f);}public OutboxEvent unfollowed(Follow f){return event("UserUnfollowed",f);}private OutboxEvent event(String type,Follow f){UUID id=UUID.randomUUID();Instant now=Instant.now();Map<String,Object>e=new LinkedHashMap<>();e.put("eventId",id);e.put("eventType",type);e.put("eventVersion",1);e.put("occurredAt",now);e.put("correlationId",ids.current());e.put("actorId",f.getFollowerId());e.put("payload",Map.of("followId",f.getId(),"followerId",f.getFollowerId(),"followedId",f.getFollowedId()));try{return new OutboxEvent(id,f.getId(),type,json.writeValueAsString(e),now);}catch(JsonProcessingException x){throw new IllegalStateException(x);}}}
